import React, { useState } from "react";
import { Mail, Lock, Eye, EyeOff } from "lucide-react";
import { useNavigate } from "react-router";

const Login = () => {
  const navigate = useNavigate();
  const [showPassword, setShowPassword] = useState(false);
  const [activeTab, setActiveTab] = useState("login");

  return (
    <div className="min-h-screen flex items-center justify-center bg-gradient-to-r from-gray-100 to-orange-50">
      {/* CARD */}
      <div className="w-full max-w-md bg-white rounded-2xl shadow-lg p-9">
        {/* Logo */}
        <div className="flex justify-center mb-4">
          <div className="w-9 h-9 bg-orange-500 rounded-lg flex items-center justify-center">
            <svg
              xmlns="http://www.w3.org/2000/svg"
              viewBox="0 0 24 24"
              fill="none"
              stroke="white"
              strokeWidth="2"
              strokeLinecap="round"
              strokeLinejoin="round"
              className="w-5 h-5"
            >
              <path d="M3 2v7c0 1.1.9 2 2 2h4a2 2 0 0 0 2-2V2" />
              <path d="M7 2v20" />
              <path d="M21 15V2a5 5 0 0 0-5 5v6c0 1.1.9 2 2 2h3Zm0 0v7" />
            </svg>
          </div>
        </div>

        {/* Title */}
        <h2 className="text-center text-xl font-bold text-gray-900">
          Welcome to FoodHub
        </h2>
        <p className="text-center text-gray-500 text-sm mt-1">
          Your favorite meals, delivered fast.
        </p>

        {/* Tabs */}
        <div className="flex mt-6 border-b">
          <button
            onClick={() => setActiveTab("login")}
            className={`flex-1 pb-2 text-sm font-medium ${
              activeTab === "login"
                ? "border-b-2 border-orange-500 text-black"
                : "text-gray-400"
            }`}
          >
            Log In
          </button>
          <button
            onClick={() => setActiveTab("signup")}
            className={`flex-1 pb-2 text-sm font-medium ${
              activeTab === "signup"
                ? "border-b-2 border-orange-500 text-black"
                : "text-gray-400"
            }`}
          >
            Sign Up
          </button>
        </div>

        {/* FORM */}
        <form className="mt-6 space-y-4">
          {/* Email */}
          <div>
            <label className="text-sm text-gray-600">Email or Phone</label>
            <div className="flex items-center border rounded-lg px-3 py-2 mt-1">
              <Mail size={16} className="text-gray-400" />
              <input
                type="text"
                placeholder="Enter email or phone number"
                className="ml-2 w-full outline-none text-sm"
              />
            </div>
          </div>

          {/* Password */}
          <div>
            <div className="flex justify-between text-sm text-gray-600">
              <label>Password</label>
              <button
                type="button"
                onClick={() => navigate("/auth/forgot-password")}
                className="text-orange-500 cursor-pointer text-xs"
              >
                Forgot?
              </button>
            </div>

            <div className="flex items-center border rounded-lg px-3 py-2 mt-1">
              <Lock size={16} className="text-gray-400" />
              <input
                type={showPassword ? "text" : "password"}
                placeholder="Enter your password"
                className="ml-2 w-full outline-none text-sm"
              />
              <button type="button" onClick={() => setShowPassword(!showPassword)}>
                {showPassword ? (
                  <EyeOff size={16} className="text-gray-400" />
                ) : (
                  <Eye size={16} className="text-gray-400" />
                )}
              </button>
            </div>
          </div>

          {/* Button */}
          <button className="w-full bg-orange-500 text-white py-3 rounded-lg font-medium hover:bg-orange-600 transition">
            Log In
          </button>
        </form>

        {/* Divider */}
        <div className="flex items-center my-6">
          <div className="flex-1 h-px bg-gray-200"></div>
          <span className="px-3 text-sm text-gray-400">Or continue with</span>
          <div className="flex-1 h-px bg-gray-200"></div>
        </div>

        {/* Social Buttons */}
        <div className="flex gap-4">
          <button className="bg-[#f4f4f4] flex-1 border py-2 rounded-lg text-sm flex items-center justify-center gap-2 hover:bg-gray-50">
            <span className="font-bold text-xl">
              <img
                alt="google img"
                className="w-10"
                src="data:image/png;base64,"
              />
            </span>{" "}
            Google
          </button>
        </div>
      </div>
    </div>
  );
};

export default Login;
